const _ = require('lodash');
const problemsData = require('../../data/problems.json');

class ProblemsService {
  /**
   * List problems with optional filters and pagination.
   * @param {Object} options
   * @param {boolean} options.includeComponents - Whether to include components metadata.
   * @param {number} options.limit - Maximum number of problems to return.
   * @param {string[]} [options.tags] - Tags to filter problems.
   * @param {string} [options.difficulty] - Difficulty filter.
   * @returns {Object} An object containing problems and metadata.
   */
  static listProblems({ includeComponents = false, limit = 50, tags = [], difficulty = null } = {}) {
    // Filter problems by tags and difficulty
    let filtered = problemsData.filter(problem => {
      if (difficulty && problem.difficulty !== difficulty) return false;
      if (tags.length > 0 && !tags.every(t => problem.tags.includes(t))) return false;
      return true;
    });

    // Limit the filtered problems
    const limited = filtered.slice(0, limit);

    const result = {
      problems: limited,
      metadata: {}
    };

    if (includeComponents) {
      // Compute componentLanguageTotals and componentStatusTotals for limited set
      const componentLanguageTotals = {};
      const componentStatusTotals = {};

      limited.forEach(problem => {
        if (!problem.components) return;
        problem.components.forEach(component => {
          // Language totals
          if (component.language) {
            componentLanguageTotals[component.language] = (componentLanguageTotals[component.language] || 0) + 1;
          }
          // Status totals
          if (component.status) {
            componentStatusTotals[component.status] = (componentStatusTotals[component.status] || 0) + 1;
          }
        });
      });

      result.metadata.componentLanguageTotals = componentLanguageTotals;
      result.metadata.componentStatusTotals = componentStatusTotals;
    }

    return result;
  }
}

module.exports = ProblemsService;
